import React, { createContext, useContext, useState, useEffect } from 'react';
import { decodeToken } from '../services/api';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [token, setToken]   = useState(() => localStorage.getItem('chap_token'));
  const [user,  setUser]    = useState(() => {
    const t = localStorage.getItem('chap_token');
    const n = localStorage.getItem('chap_name');
    if (t) { const d = decodeToken(t); return { ...d, name: n || d.email }; }
    return null;
  });

  const login = (token, name) => {
    const decoded = decodeToken(token);
    const u = { ...decoded, name: name || decoded.email };
    localStorage.setItem('chap_token', token);
    localStorage.setItem('chap_name',  u.name);
    setToken(token);
    setUser(u);
  };

  const logout = () => {
    localStorage.removeItem('chap_token');
    localStorage.removeItem('chap_name');
    setToken(null);
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ token, user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);
